import React from 'react';
import '../App.css';

const Home = () => {
  return (
    <div className="content-section">
      <h1>Welcome to Connectonic</h1>
      <p>
        Your trusted partner in building amazing web experiences. We specialize in
        creating modern, responsive, and user-friendly websites and applications.
      </p>
      <img src="https://placehold.co/800x400.png" alt="Digital Connection" data-ai-hint="digital connection" className="responsive-image" />
    </div>
  );
};

export default Home;
